import dspy

class IntentClassifier(dspy.Signature):
    '''Classify email processing intent.'''
    email_content = dspy.InputField()
    intent = dspy.OutputField(desc='reply|draft|forward|archive')

class IntentModule(dspy.Module):
    def __init__(self):
        super().__init__()
        self.classify = dspy.ChainOfThought(IntentClassifier)

    def forward(self, email_content: str) -> dspy.Prediction:
        return self.classify(email_content=email_content)

# Usage
lm = dspy.OpenAI(model='gpt-4')
dspy.settings.configure(lm=lm)
module = IntentModule()
result = module('Urgent: Review Q4 financials')

class DraftGenerator(dspy.Signature):
    '''Generate professional email draft.'''
    intent: str = dspy.InputField()
    context: str = dspy.InputField()
    draft: str = dspy.OutputField(desc='Professional email draft, max 200 words')

class DraftModule(dspy.Module):
    def __init__(self):
        super().__init__()
        self.generate = dspy.ChainOfThought(DraftGenerator)

    def forward(self, intent: str, context: str) -> dspy.Prediction:
        return self.generate(intent=intent, context=context)

# Optimized usage
module = DraftModule()
result = module('reply', 'Customer reported billing issue on invoice #12345')

class AttachmentAnalyzer(dspy.Signature):
    '''Analyze email attachment content.'''
    filename: str = dspy.InputField()
    content_summary: str = dspy.InputField()
    action = dspy.OutputField(desc='include|exclude|redact|flag')
    reason: str = dspy.OutputField(desc='Brief explanation')

class AttachmentModule(dspy.Module):
    def __init__(self):
        super().__init__()
        self.analyze = dspy.ChainOfThought(AttachmentAnalyzer)

    def forward(self, filename: str, content_summary: str) -> dspy.Prediction:
        return self.analyze(filename=filename, content_summary=content_summary)

module = AttachmentModule()
result = module('financials.xlsx', 'Contains Q4 revenue data and employee salaries')

class ApprovalChain(dspy.Module):
    def __init__(self):
        super().__init__()
        self.intent = IntentModule()
        self.draft = DraftModule()
        self.attach = AttachmentModule()

    def forward(self, email_content: str, recipient: str) -> dict:
        intent_pred = self.intent(email_content)
        draft_pred = self.draft(intent_pred.intent, email_content)
        attach_pred = self.attach('invoice.pdf', 'Billing details')

        return {
            'intent': intent_pred.intent,
            'draft': draft_pred.draft,
            'attachments': [attach_pred.action],
            'approved': 'pending'
        }

